  const hours = Math.max(durationSeconds / 3600, 1 / 60);
  const pointDensity = pointCount / Math.max(distanceMiles, 0.1);
  const baseGps = Math.round(distanceMiles * 120 + Math.min(160, pointDensity * 2) + Math.min(100, avgMph * 20));
  const routine = walkRoutineStats(savedWalks, { startedAt: Date.now() });
  const gpsPoints = Math.round(baseGps * routine.routineMultiplier);
  const weightKg = Number(hiker.weightLb || 180) * 0.453592;
  const caloriesBurned = Math.round(Math.max(0, (2.8 + Math.min(avgMph, 5) * 0.9) * weightKg * hours));
  const caloriesIn = foodCalories(hiker);
  const targetWater = Math.max(8, hours * (18 + (Number(conditions.tempF) > 75 ? 8 : 0) + (Number(conditions.humidity) > 65 ? 4 : 0)));
  const waterScore = Math.min(40, Math.round((Number(hiker.waterOz || 0) / targetWater) * 40));
  const fuelScore = Math.min(35, Math.round((caloriesIn / Math.max(150, caloriesBurned * 0.65)) * 35));
  const burnScore = Math.min(25, Math.round(Math.min(1.3, caloriesBurned / 350) * 25));
