function Navigate({ recording, setRecording, elapsed, progress, setProgress, resetTrack, selectedRoute = primaryRoutePack, launchPlan = {}, completedTrails = [], onCompleteRoute }) {
  const [navTrace, setNavTrace] = useState([]);
  const [navStatus, setNavStatus] = useState('Ready. Start recording to use phone GPS on the selected trail.');
  const secure = typeof window !== 'undefined' && window.isSecureContext;
  const navWaypoints = [...(selectedRoute.waypoints || []), ...(selectedRoute.customWaypoints || [])].sort((a, b) => Number(a.mile || 0) - Number(b.mile || 0));
  const latest = navTrace.at(-1) || routePointAt(selectedRoute, progress);
  const routeStatus = routeStatusForPoint(selectedRoute, latest, navWaypoints);
  useEffect(() => {
    setNavTrace([]);
    setNavStatus(`Selected ${selectedRoute.name}. Route line and waypoints loaded.`);
  }, [selectedRoute?.id]);
  useEffect(() => {
    if (!recording) return undefined;
    let watchId;
    if (navigator.geolocation && secure) {
      setNavStatus('Live phone GPS active for selected trail. Keep screen awake for best tracking.');
      watchId = navigator.geolocation.watchPosition(pos => {
        const point = { lat: pos.coords.latitude, lon: pos.coords.longitude, accuracy: pos.coords.accuracy, t: Date.now() };
        const status = routeStatusForPoint(selectedRoute, point, navWaypoints);
        setNavTrace(trace => [...trace, point].slice(-1500));
        setProgress(status.progress);
        setNavStatus(`Live GPS · accuracy ${Math.round(pos.coords.accuracy || 0)} m · ${status.offRouteFeet} ft from route`);
      }, err => setNavStatus(`GPS unavailable: ${err.message}. Simulator will keep route preview moving.`), { enableHighAccuracy: true, maximumAge: 1500, timeout: 15000 });
    } else {
      setNavStatus('Simulator route preview running. Use Tailscale HTTPS on phone for real GPS.');
      const id = setInterval(() => {
        setProgress(p => {
          const next = p >= 0.99 ? 0 : Math.min(0.99, p + 0.01);
          setNavTrace(trace => [...trace, { ...routePointAt(selectedRoute, next), accuracy: 20, t: Date.now() }].slice(-1500));
          return next;
        });
      }, 1000);
      return () => clearInterval(id);
    }
    return () => watchId && navigator.geolocation.clearWatch(watchId);
  }, [recording, secure, selectedRoute?.id, setProgress]);
  const miles = routeStatus.milesIn;
  const pct = Math.round(routeStatus.progress * 100);
  const alreadyComplete = completedTrails.some(item => item.routeId === selectedRoute.id);
  const completeRoute = () => onCompleteRoute && onCompleteRoute({ routeId: selectedRoute.id, routeName: selectedRoute.name, miles: Number(selectedRoute.distanceMiles || selectedRoute.miles || 0), completedAt: Date.now(), durationSeconds: elapsed, source: secure && navTrace.length ? 'phone GPS / local' : 'manual/simulated', progress: pct });
  return <><section className="map-card"><div className="map-toolbar"><Pill>Selected trail</Pill><Pill tone={secure ? 'online' : 'warn'}>{secure ? 'GPS capable' : 'HTTP/no GPS'}</Pill><Pill tone={recording ? 'recording' : 'default'}>{recording ? 'REC' : 'ready'}</Pill><Pill>{selectedRoute.name}</Pill>{launchPlan.turnAroundTime && <Pill tone="warn">turn {launchPlan.turnAroundTime}</Pill>}{launchPlan.trailLeaveTime && <Pill tone="warn">leave {launchPlan.trailLeaveTime}</Pill>}</div><LiveLeafletMap trace={navTrace} center={[latest.lat, latest.lon]} active={recording} route={selectedRoute} waypoints={navWaypoints} /></section><section className="panel dashboard-panel"><div className="section-head"><div><h2>Active hike navigation</h2><p className="muted">{selectedRoute.name} · live view follows route geometry, built-in waypoints, custom waypoints, and phone GPS when available.</p></div><div className="button-row"><button className="primary small" onClick={() => setRecording(!recording)}>{recording ? 'Pause recording' : 'Start recording'}</button><button className="ghost small" onClick={() => { setNavTrace([]); resetTrack(); }}>Reset</button></div></div><div className="completion-card"><div className="completion-head"><strong>{pct}% complete</strong><span>{miles.toFixed(2)} / {Number(selectedRoute.distanceMiles || selectedRoute.miles || 0).toFixed(2)} mi</span></div><div className="completion-bar"><span style={{ width: `${Math.min(100, Math.max(0, pct))}%` }} /></div><div className="button-row"><button className="ghost small" onClick={completeRoute}>{alreadyComplete ? 'Save another completion' : 'Mark trail complete'}</button><Pill>{alreadyComplete ? 'completed before' : 'local completion log'}</Pill></div><p className="muted">Completion saves locally now. Supabase later can sync completed trails, repeat attempts, miles, and profile stats.</p></div><div className="nav-grid"><Stat value={miles.toFixed(2)} label="mi tracked" /><Stat value={formatClock(elapsed)} label="elapsed" /><Stat value={routeStatus.milesRemaining.toFixed(2)} label="mi remaining" /><Stat value={`${routeStatus.offRouteFeet} ft`} label="from route" /><Stat value={routeStatus.nextWaypoint?.name || 'Finish'} label="next waypoint" /><Stat value={routeStatus.nextWaypoint?.mile ?? selectedRoute.distanceMiles} label="next mi" /><Stat value={selectedRoute.difficulty} label="difficulty" /><Stat value={`${pct}%`} label="route progress" /></div><div className={`alert ${routeStatus.offRouteFeet > 250 ? 'warn' : 'info'}`}>{navStatus}{routeStatus.offRouteFeet > 250 ? ' · Check map/compass: you may be off the selected trail corridor.' : ''}</div><ReadyChecklist route={selectedRoute} secure={secure} conditions={{ source: 'route/local' }} /></section></>;
}
