    const marker = { id: `dog-stop-${Date.now()}`, name: `Dog stop ${stopMarkers.length + 1}`, type: 'Dog stop', icon: '🐾', mile: Number(estMiles.toFixed(2)), lat: point.lat, lon: point.lon, t: Date.now(), notes: `Marked at ${formatTimeOnly(Date.now())}`, custom: true };
