    const finished = { ...walk, active: false, endedAt, name: `Walk ${formatDateTime(walk.startedAt || endedAt)}`, distanceMiles: estMiles, durationSeconds: walkDurationSeconds({ ...walk, endedAt }), averageMph: finishedScores.avgMph, pointCount: trace.length, stopMarkers, gpsPoints: finishedScores.gpsPoints, healthScore: finishedScores.healthScore, navigationScore: finishedScores.navigationScore, caloriesBurned: finishedScores.caloriesBurned, routine: finishedScores.routine, savedAt: endedAt, source: walk.source || (secure ? 'phone GPS' : 'simulator') };
