  useEffect(() => { if (accountState.active !== 'Guest') return undefined; const clear = () => clearGuestData(); window.addEventListener('beforeunload', clear); return () => window.removeEventListener('beforeunload', clear); }, [accountState.active]);
  const activeOwner = accountState.active || 'Guest';
  const saveCloudRecord = async (kind, payload) => {
    const result = await createMapPiRecord({ owner: activeOwner, deviceId, kind, payload: { ...payload, appVersion: VERSION, syncedAt: new Date().toISOString() } });
    if (!result.ok) throw new Error(result.error || 'Supabase sync failed');
    return result.data;
  };
