  const onCompleteRoute = async (entry) => { const saved = { ...entry, id: `complete-${Date.now()}` }; setCompletedTrails(items => [saved, ...items].slice(0, 100)); try { if (supabaseConfig.enabled) { await saveCloudRecord('completed_trail', saved); setGpxStatus(`Saved completed trail locally and synced to Supabase: ${entry.routeName}.`); } else { setGpxStatus(`Saved completed trail locally: ${entry.routeName}. Add Vercel Supabase env vars for cloud sync.`); } } catch (err) { setGpxStatus(`Saved locally, but cloud sync failed: ${err.message}`); } };
  const onExportGpx = () => { downloadTextFile('mappi3-selected-route.gpx', makeGpx(selectedRoute), 'application/gpx+xml'); setGpxStatus(`Exported mappi3-selected-route.gpx from ${selectedRoute.name}.`); }; const onExportRouteGpx = (route) => downloadTextFile(`${(route.name || 'mappi3-route').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeRouteGpx(route), 'application/gpx+xml'); const onExportWalkGpx = (item) => downloadTextFile(`${(item.name || 'mappi3-walk').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeWalkGpx(item), 'application/gpx+xml'); const onDeleteWalk = (id) => setSavedWalks(items => items.filter(item => (item.id || item.savedAt) !== id)); const onImportGpx = () => setGpxStatus('GPX import UI is ready; file parsing is the next production data step so verified tracks can replace rough seed geometry.'); const clearLocalState = () => { ['mappi3.activeTab','mappi3.originPoint','mappi3.selectedRouteId','mappi3.searchQuery','mappi3.settings','mappi3.routes','mappi3.elapsed','mappi3.progress','mappi3.hiker','mappi3.completedTrails','mappi3.healthHistory','mappi3.customWaypointsByRoute','mappi3.conditions','mappi3.walk','mappi3.walkHistory','mappi3.launchChecklist','mappi3.launchPlan','mappi3.readinessLog'].forEach(k => localStorage.removeItem(k)); location.reload(); }; const goTab = (delta) => { const index = tabs.indexOf(activeTab); setActiveTab(tabs[(index + delta + tabs.length) % tabs.length]); }; const onTouchStart = (event) => { if (event.target.closest('input, textarea, select, button, .leaflet-container')) return; touchStartX.current = event.touches[0].clientX; }; const onTouchEnd = (event) => { if (touchStartX.current === null) return; const dx = event.changedTouches[0].clientX - touchStartX.current; touchStartX.current = null; if (Math.abs(dx) > 70) goTab(dx < 0 ? 1 : -1); }; const onUsePhoneLocation = () => { if (!navigator.geolocation || !secure) { setGpxStatus('Phone location needs the Tailscale HTTPS URL and browser location permission.'); return; } navigator.geolocation.getCurrentPosition(pos => { setOriginPoint({ label: `phone GPS ±${Math.round(pos.coords.accuracy || 0)}m`, lat: pos.coords.latitude, lon: pos.coords.longitude }); setGpxStatus('Phone GPS origin saved for trailhead travel estimate.'); }, err => setGpxStatus(`Phone GPS origin unavailable: ${err.message}`), { enableHighAccuracy: true, maximumAge: 60000, timeout: 12000 }); };
  return <main className="app-shell" onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}><section className="hero-card"><div className="top-line"><span className="brand-mark">△</span><div><h1>MapPi3</h1><p>Trail OS · {VERSION}</p></div><Pill tone="online">{settings.mode}</Pill></div><div className="search-box"><span>⌕</span><input placeholder="Search places, trails, foods, water, saved GPX…" value={searchQuery} onChange={e => { setSearchQuery(e.target.value); setActiveTab('Explore'); }} /><button className="ghost small" onClick={() => setSearchQuery('')}>Clear</button></div><div className="route-quick-filters">{routeQuickFilters.map(filter => <button key={filter} onClick={() => { setSearchQuery(filter); setActiveTab('Explore'); }}>{filter}</button>)}<button onClick={onUsePhoneLocation}>use current GPS</button><label className="radius-control">radius <select value={settings.searchRadiusMiles ?? 80} onChange={e => setSettings(s => ({ ...s, searchRadiusMiles: e.target.value === 'all' ? 'all' : Number(e.target.value) }))}><option value={25}>25 mi</option><option value={80}>80 mi</option><option value={150}>150 mi</option><option value={300}>300 mi</option><option value="all">all</option></select></label></div><div className="search-hint">{searchQuery ? `${filteredRoutes.length} route match(es) inside current radius. Food/drink custom entry lives in Health.` : 'Type in search to show route results. Nothing is auto-populated until you search.'}</div><div className="quick-stats"><Stat value={(progress * (selectedRoute.miles || selectedRoute.distanceMiles || primaryRoutePack.distanceMiles)).toFixed(1)} label="hike mi" /><Stat value={formatClock(elapsed)} label="elapsed" /><Stat value={Math.round(healthMetrics.caloriesBurned)} label="cal burned" /><Stat value={`${downloadedCount}/${routes.length}`} label="packs local" /><Stat value={completedTrails.length} label="trails done" /></div></section><section className="tabs-grid" aria-label="MapPi3 sections">{tabs.map(item => <button key={item} className={item === activeTab ? 'active' : ''} onClick={() => setActiveTab(item)}>{item}</button>)}</section><ActiveTab activeTab={activeTab} routes={filteredRoutes} allRoutes={routes} originPoint={originPoint || localHome} searchRadiusMiles={settings.searchRadiusMiles ?? 80} searchQuery={searchQuery} selectedRoute={selectedRoute} customWaypoints={customWaypoints} setCustomWaypoints={setCustomWaypoints} routeDirty={routeDirty} onSaveRoutePack={saveRoutePack} onDuplicateRoutePack={duplicateRoutePack} onExportRouteJson={exportRouteJson} onImportRoutePack={importRoutePack} onUpdateRouteStyle={updateRouteStyle} onExportRouteJsonFor={exportRouteJsonFor} onDeleteRoutePack={deleteRoutePack} onDeleteOfflinePack={deleteOfflinePack} onRefreshOfflinePack={refreshOfflinePack} secure={secure} conditions={conditions} onUsePhoneLocation={onUsePhoneLocation} launchChecklist={launchChecklist} setLaunchChecklist={setLaunchChecklist} launchPlan={launchPlan} completedTrails={completedTrails} onCompleteRoute={onCompleteRoute} setLaunchPlan={setLaunchPlan} readinessLog={readinessLog} setReadinessLog={setReadinessLog} onSelectRoute={(id) => { setSelectedRouteId(id); setActiveTab('Plan'); }} setSelectedRoute={(route) => setSelectedRouteId(route?.id)} onStartRoute={onStartRoute} onExportRouteGpx={onExportRouteGpx} onDownload={onDownload} accountState={accountState} setAccountState={setAccountState} clearGuestData={clearGuestData} deviceId={deviceId} syncStatus={syncStatus} onSyncDeviceSettings={onSyncDeviceSettings} onPullCloudRecords={onPullCloudRecords} settings={settings} setSettings={setSettings} recording={recording} setRecording={setRecording} elapsed={elapsed} progress={progress} setProgress={setProgress} resetTrack={resetTrack} gpxStatus={gpxStatus} onExportGpx={onExportGpx} onImportGpx={onImportGpx} clearLocalState={clearLocalState} hiker={hiker} setHiker={setHiker} healthHistory={healthHistory} setHealthHistory={setHealthHistory} conditions={conditions} setConditions={setConditions} walk={walk} setWalk={setWalk} savedWalks={savedWalks} setSavedWalks={setSavedWalks} onExportWalkGpx={onExportWalkGpx} onDeleteWalk={onDeleteWalk} /></main>;
